2.query:
// 1. Gather data for the timeseries chart
timeseries {
  requests_sampled = sum(dt.sfm.oneagent.code_module.requests.sampled), 
  requests_processed = sum(dt.sfm.oneagent.code_module.requests.processed),
  traces_sampled = sum(dt.sfm.oneagent.code_module.traces.sampled), 
  traces_processed = sum(dt.sfm.oneagent.code_module.traces.processed)
}, nonempty:true

// 2. Create the data that will be visualized in the chart
| fieldsAdd `trace capture rate`=traces_sampled[]/traces_processed[]*100
| fieldsAdd `trace capture rate`=if(`trace capture rate`[] > 100, 100, else: `trace capture rate`[])
| fieldsAdd `request capture rate`=requests_sampled[]/requests_processed[]*100
| fieldsAdd `request capture rate`=if(`request capture rate`[] > 100, 100, else: `request capture rate`[])

// 3. Remove data that is of no use anymore
| fieldsRemove traces_sampled, traces_processed, requests_sampled, requests_processed

3.query:
// 1. Create basic timeseries
timeseries { 
	included_limit=avg(dt.billing.traces.maximum_included_fullstack_volume_per_minute), 
	configured_limit=avg(dt.billing.traces.maximum_configured_fullstack_volume_per_minute)
}, interval:1h, nonempty:true

// 2. Add computed fields to the timeseries
| fieldsAdd intervalInMinutes = toLong(interval) / 60000000000
| fieldsAdd configured_limit = configured_limit[] * intervalInMinutes
| fieldsAdd included_limit = included_limit[] * intervalInMinutes

// 3. Add full-stack traces ingest events to the timeseries
| append [
	fetch dt.system.events
	| filter event.type == "Traces - Ingest & Process"
	| filter licensing_type == "fullstack-adaptive" or licensing_type == "fullstack-fixed-rate" 
	| makeTimeseries ingested_bytes_sum = sum(ingested_bytes), time: usage.start, interval:1h, by: {licensing_type}, nonempty:true
]

10.query:
// 1. Create basic timeseries
timeseries { 
	configured_limit=avg(dt.billing.traces.maximum_configured_fullstack_volume_per_minute)
} , interval:15m, nonempty:true

// 2. Add computed fields to the timeseries
| fieldsAdd intervalInMinutes = toLong(interval) / 60000000000
// As we are using "maximum_configured_fullstack_volume_per_minute" and an interval of 15m we need to multiply them
| fieldsAdd configured_limit = configured_limit[] * intervalInMinutes

// 3. Join full-stack traces ingest events to the timeseries
| join [
	fetch dt.system.events
	| filter event.type == "Traces - Ingest & Process"
	| filter licensing_type == "fullstack-adaptive" or licensing_type == "fullstack-fixed-rate" 
	| makeTimeseries ingested_bytes_sum = sum(ingested_bytes), time: usage.start, interval:15m, nonempty:true
], on:{timeframe}, fields:{ingested_bytes_sum}

// 4. Compute a field based on the previous join, then delete the field added by the join
| fieldsAdd volume_used=ingested_bytes_sum[]/configured_limit[] * 100
| fieldsRemove configured_limit, ingested_bytes_sum

